class Solution {
public:
    int numberOfWays(int n, int x, int y) {
        const int MOD = 1e9 + 7;
        long long res = 1;
        for (int i = 0; i < n; i++) {
            res = (res * x) % MOD;
        }
        res = (res * pow(y, x)) % MOD;
        return res;
    }
    long long pow(long long a, long long b) {
        const int MOD = 1e9 + 7;
        long long res = 1;
        while (b > 0) {
            if (b & 1) {
                res = (res * a) % MOD;
            }
            a = (a * a) % MOD;
            b >>= 1;
        }
        return res;
    }
};

